// Get document text from either fetch result or direct input
let documentText = '';

// Check if we came from Fetch Document From URL
const fetchNode = $('Fetch Document From URL');
if (fetchNode && fetchNode.all && fetchNode.all().length > 0) {
  try {
    const fetchedItem = fetchNode.first();
    if (fetchedItem && fetchedItem.json && fetchedItem.json.data) {
      documentText = String(fetchedItem.json.data);
    } else if (fetchedItem && fetchedItem.json && fetchedItem.json.body) {
      documentText = String(fetchedItem.json.body);
    }
  } catch(e) {
    // fall through to current item
  }
}

// If not from fetch, use direct text from current item or Extract node
if (!documentText || documentText.trim() === '') {
  documentText = $json.document_text || '';
}

if (!documentText || documentText.trim() === '') {
  try {
    const extractNode = $('Extract And Validate Input').first();
    documentText = extractNode.json.document_text || '';
  } catch(e) {
    documentText = '';
  }
}

// Get metadata from Extract And Validate Input node
let doc_id = 'doc-unknown';
let reg = 'HIPAA';
try {
  const extractItem = $('Extract And Validate Input').first();
  doc_id = extractItem.json.document_id || 'doc-unknown';
  reg = extractItem.json.regulation || 'HIPAA';
} catch(e) {
  doc_id = $json.document_id || 'doc-unknown';
  reg = $json.regulation || 'HIPAA';
}

// Split document into clauses
let clauses = [];

// Try splitting on numbered headings first
const numberedHeadingPattern = /(?=(?:^|\n)\s*(?:Section\s+\d+|Article\s+\d+|ARTICLE\s+\d+|SECTION\s+\d+|\d+\.\s+[A-Z]))/;
const trySplit = documentText.split(numberedHeadingPattern).map(s => s.trim()).filter(s => s.length > 20);

if (trySplit.length > 1) {
  clauses = trySplit;
} else {
  // Fall back to double newline paragraph breaks
  clauses = documentText.split(/\n\s*\n/).map(s => s.trim()).filter(s => s.length > 20);
}

// Filter out empty/whitespace-only clauses
clauses = clauses.filter(c => c && c.trim().length > 0);

// Limit to max 20 clauses
if (clauses.length > 20) {
  clauses = clauses.slice(0, 20);
}

// If no clauses found, treat entire document as one clause
if (clauses.length === 0) {
  clauses = [documentText.trim() || 'No document text provided.'];
}

// Return array of items, one per clause
return clauses.map((clauseText, index) => ({
  json: {
    clause_id: doc_id + '-clause-' + index,
    clause_text: clauseText,
    clause_index: index,
    document_id: doc_id,
    regulation: reg,
    total_clauses: clauses.length
  }
}));

