// Get LLM text response
const rawResponse = $json.text || $json.output || $json.response || '';

let parsed = null;

// Attempt 1: Direct JSON.parse
try {
  parsed = JSON.parse(rawResponse);
} catch(e1) {
  // Attempt 2: Extract from markdown fences
  try {
    const fenceMatch = rawResponse.match(/```json\s*([\s\S]*?)\s*```/);
    if (fenceMatch && fenceMatch[1]) {
      parsed = JSON.parse(fenceMatch[1].trim());
    }
  } catch(e2) {
    // Attempt 3: Find first { to last }
    try {
      const firstBrace = rawResponse.indexOf('{');
      const lastBrace = rawResponse.lastIndexOf('}');
      if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
        const jsonSubstring = rawResponse.substring(firstBrace, lastBrace + 1);
        parsed = JSON.parse(jsonSubstring);
      }
    } catch(e3) {
      parsed = null;
    }
  }
}

// Valid status values
const validStatuses = ['Compliant', 'Non-Compliant', 'Ambiguous'];

// Fallback if parsing failed entirely
if (!parsed || typeof parsed !== 'object') {
  return [{
    json: {
      clause_id: $json.clause_id || 'unknown',
      status: 'Ambiguous',
      risk_score: 50,
      regulation_citation: 'N/A',
      explanation: 'LLM output parsing failed.',
      suggested_fix: 'Manual review required.',
      document_id: $json.document_id || '',
      regulation: $json.regulation || 'HIPAA',
      clause_index: $json.clause_index || 0,
      total_clauses: $json.total_clauses || 1
    }
  }];
}

// Validate and sanitize fields

// clause_id: use parsed or fallback to input
if (!parsed.clause_id || typeof parsed.clause_id !== 'string') {
  parsed.clause_id = $json.clause_id || 'unknown';
}

// status: must be one of the valid values
if (!validStatuses.includes(parsed.status)) {
  parsed.status = 'Ambiguous';
}

// risk_score: must be 0-100 integer
let score = parseInt(parsed.risk_score, 10);
if (isNaN(score)) score = 50;
if (score < 0) score = 0;
if (score > 100) score = 100;
parsed.risk_score = score;

// regulation_citation
if (!parsed.regulation_citation || typeof parsed.regulation_citation !== 'string') {
  parsed.regulation_citation = 'N/A';
}

// explanation
if (!parsed.explanation || typeof parsed.explanation !== 'string') {
  parsed.explanation = 'No explanation provided.';
}

// suggested_fix
if (!parsed.suggested_fix || typeof parsed.suggested_fix !== 'string') {
  parsed.suggested_fix = parsed.status === 'Compliant' ? 'N/A' : 'Manual review required.';
}

// Pass through metadata
parsed.document_id = $json.document_id || '';
parsed.regulation = $json.regulation || 'HIPAA';
parsed.clause_index = $json.clause_index !== undefined ? $json.clause_index : 0;
parsed.total_clauses = $json.total_clauses || 1;

return [{ json: parsed }];

// Collect all items
const items = $input.all();
const clauseResults = items.map(item => item.json);

// Get metadata from first item
const firstItem = clauseResults[0] || {};
const document_id = firstItem.document_id || 'unknown';
const regulation = firstItem.regulation || 'HIPAA';
const total_clauses = clauseResults.length;

// Count by status
let non_compliant_count = 0;
let ambiguous_count = 0;
let compliant_count = 0;

// Weighted risk score calculation
let weightedSum = 0;
let totalWeight = 0;

for (const clause of clauseResults) {
  const status = clause.status || 'Ambiguous';
  const riskScore = typeof clause.risk_score === 'number' ? clause.risk_score : 50;

  let weight = 1.0;
  if (status === 'Non-Compliant') {
    weight = 1.5;
    non_compliant_count++;
  } else if (status === 'Ambiguous') {
    weight = 1.0;
    ambiguous_count++;
  } else {
    weight = 0.5;
    compliant_count++;
  }

  weightedSum += riskScore * weight;
  totalWeight += weight;
}

// Calculate overall risk score
const overall_risk_score = totalWeight > 0 ? Math.round(weightedSum / totalWeight) : 0;

// Determine risk level
let risk_level = 'LOW';
if (overall_risk_score > 70) {
  risk_level = 'HIGH';
} else if (overall_risk_score >= 30) {
  risk_level = 'MEDIUM';
}

return [{
  json: {
    document_id,
    regulation,
    overall_risk_score,
    risk_level,
    total_clauses,
    non_compliant_count,
    ambiguous_count,
    compliant_count,
    clause_results: clauseResults,
    analyzed_at: new Date().toISOString()
  }
}];

